class Solution:
    def evenOddBit(self, n: int) -> List[int]:
        bin_str = bin(n)[2:]
        even = odd = 0
        for i, bit in enumerate(bin_str):
            if bit == '1':
                if i % 2 == 0:
                    even += 1
                else:
                    odd += 1
        return [even, odd]

